// LAYER 1+2: Extract & Validate (§3.3 GEMINI.md)
// Zero-throw: returns Standard Contract error, never throws
const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Cancel_Booking', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}

const booking_id = String(input.booking_id || '').trim();
if (!booking_id) return ve('MISSING_FIELD', 'booking_id is required');
if (!UUID_RE.test(booking_id)) return ve('INVALID_TYPE', 'booking_id must be a UUID');

let cancellation_reason = String(input.cancellation_reason || '').trim() || null;
if (cancellation_reason && cancellation_reason.length > 500) return ve('INVALID_INPUT', 'Reason too long (max 500 chars)');

// Sanitize for SQL (escape single quotes)
const booking_id_sanitized = booking_id.replace(/'/g, "''");
const cancellation_reason_sanitized = cancellation_reason ? cancellation_reason.replace(/'/g, "''") : null;

return [{ json: {
  success: true,
  booking_id,
  booking_id_sanitized,
  cancellation_reason,
  cancellation_reason_sanitized,
  _validated: true
}}];

// LAYER 3: Build Check Query (§3.3 GEMINI.md)
const input = $input.first().json;
if (input._exit_early) return [{ json: input }];

// Union trick ensures at least one row is returned (avoids n8n stopping on empty result)
const query = `
SELECT id, status FROM bookings WHERE id = '${input.booking_id_sanitized}'::uuid
UNION ALL
SELECT NULL as id, 'NOT_FOUND' as status
LIMIT 1;
`;

return [{ json: { ...input, check_query: query }}];

// Gate Execute - solo pasa items válidos
const input = $input.first().json;
if (input._exit_early) return [];
return [{ json: input }];

// Gate Skip - solo pasa errores de validación
const input = $input.first().json;
if (!input._exit_early) return [];
return [{ json: input }];

// Route By Check Result - Gate+Skip pattern
const pg = $input.first().json;
const upstream = $('Validate Input').first().json;

if (upstream._exit_early) return [{ json: upstream }];

// Handle DB Error
if (pg.error && pg.error.message) {
  return [{ json: {
    success: false, error_code: 'DB_CHECK_ERROR', error_message: pg.error.message,
    _meta: { source: 'DB_Cancel_Booking', timestamp: new Date().toISOString() },
    _exit_early: true,
    _route: 'error'
  }}];
}

// Check found (pg.status === 'NOT_FOUND' means the union dummy row was returned)
if (!pg.id || pg.status === 'NOT_FOUND') {
  return [{ json: {
    success: false, error_code: 'NOT_FOUND', error_message: 'Booking not found',
    _meta: { source: 'DB_Cancel_Booking', timestamp: new Date().toISOString() },
    _exit_early: true,
    _route: 'error'
  }}];
}

// Check status
if (pg.status === 'CANCELLED') {
  return [{ json: {
    success: false, error_code: 'ALREADY_CANCELLED', error_message: 'Already cancelled',
    data: { booking_id: pg.id, status: pg.status },
    _meta: { source: 'DB_Cancel_Booking', timestamp: new Date().toISOString() },
    _exit_early: true,
    _route: 'error'
  }}];
}

// OK to cancel - build cancel query
const bid = pg.id.replace(/'/g, "''");
const reason = upstream.cancellation_reason_sanitized;
const cancel_query = `UPDATE bookings SET status = 'CANCELLED', cancelled_at = NOW(), cancellation_reason = ${reason ? `'${reason}'` : 'NULL'} WHERE id = '${bid}'::uuid RETURNING id, status;`;

return [{ json: {
  ...upstream,
  ...pg,
  _route: 'execute',
  cancel_query
}}];

// Gate Execute Cancel - solo pasa items con _route: execute
const input = $input.first().json;
if (input._route !== 'execute') return [];
return [{ json: input }];

// Gate Skip Cancel - solo pasa errores
const input = $input.first().json;
if (input._route === 'execute') return [];
return [{ json: input }];

// STEP 5: Final Response - Standard Contract (§3.2)
const current = $input.first().json;

// Detect state
const hasError = !!(current.error || current.error_code || current.success === false);
const isSuccess = !hasError && !!(current.success === true || current.id || current.booking_id);

const response = {
  success: isSuccess,
  error_code: current.error_code || (current.error ? 'DB_ERROR' : null),
  error_message: current.error_message || current.error?.message || null,
  data: isSuccess ? { 
    booking_id: current.id || current.booking_id, 
    status: current.status || 'CANCELLED', 
    cancelled: true 
  } : (current.data || null),
  _meta: current._meta || { 
    source: 'DB_Cancel_Booking', 
    timestamp: new Date().toISOString(), 
    workflow_id: $workflow.id 
  }
};

return [{ json: response }];
